	&lt;li&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;The Himalayas extend over&lt;/span&gt;&lt;b style=&quot;color: rgb(32, 33, 36);   &quot;&gt;&amp;nbsp;the northeastern portion of India&lt;/b&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;.&lt;/span&gt;&lt;/li&gt;
