&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;color: rgb(32, 33, 36);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;पश्चिमी घाट दक्कन के पठार की&lt;strong&gt; पहाड़ी आलोचना और बर्बाद किनारे हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;हिमालय भारत के पूर्वोत्तर भाग पर फैला हुआ है&lt;/strong&gt;&lt;span style=&quot;color: rgb(32, 33, 36);&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पूर्वी घाट&lt;/strong&gt; &lt;strong&gt;भारत के पूर्वी तट के माध्यम से पहाड़ों की एक आंतरायिक शृंखला&lt;/strong&gt; है।&lt;/li&gt;
